"""
MKT Original Commentary — Luke chapters 12–13
Run: python3 scripts/zc-original-luke-12-13.py

Source data used:
- data/interlinear/luke.json
- data/translation/draft/mediating/luke.json
- data/translation/glossary-greek.json

Key decisions in this range:
- 12:10: blasphemy against the Holy Spirit is unforgivable; the specific sin is
  persistent, final rejection of the Spirit's testimony — not a momentary lapse.
- 12:20: "apaitousin" — they demand back your soul; the divine passive with
  plural subject ("they") follows the Semitic idiom for impersonal divine action.
- 12:49-50: "baptisma" in v.50 is Jesus's first explicit Passion reference using
  the baptism metaphor (cf. Mk 10:38-39); "fire" in v.49 is the eschatological
  purification of Isa 66:15-16, Joel 2:30-31, Mal 3:2-3.
- 13:16: "thygatera Abraam" (daughter of Abraham) — the title restores the woman's
  covenant status; being bound by Satan does not remove one's identity as heir of
  the covenant.
- 13:33: "dei me semeron kai aurion kai tē echomenē poreuesthai" — dei (divine
  necessity) marks Jerusalem as the appointed place of prophetic death.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE = {
  "12": {
    "1": '<p><strong>En hois episynachtheisōn tōn myriasōn tou ochlou</strong> — while ten-thousands of the crowd had gathered — <em>myrias</em> (myriad, ten thousand — often used hyperbolically for an uncountable crowd) marks the mass context for the following private instruction to disciples. <strong>ērxato legein pros tous mathētas autou prōton</strong> — he began to say to his disciples first — the audience distinction is structural: vv.1-12 address disciples privately; vv.13ff address the crowd. <strong>Prosexete heautois apo tēs zymēs, hētis estin hypokrisis, tōn Pharisaiōn</strong> — guard yourselves from the yeast, which is hypocrisy, of the Pharisees — <em>zymē</em> (yeast, leaven — a small agent that pervades the whole) is Paul\'s metaphor for sin in 1 Cor 5:6-8; Gal 5:9. Luke defines the yeast explicitly: <em>hypokrisis</em> (hypocrisy, playing a role, mask-wearing — the actor\'s term) is the gap between public presentation and inner reality.</p>',
    "2": '<p><strong>ouden de synkekalymmenon estin ho ouk apokalyphthēsetai</strong> — nothing has been covered that will not be uncovered — the aphorism (cf. 8:17) grounds the call to genuine rather than performed religion: ultimate disclosure makes hypocrisy futile. <em>Synkalyptō</em> (to cover over, conceal thoroughly) and <em>apokalyptō</em> (to uncover, reveal — the apocalypsis root) are the antonyms of concealment and disclosure. <strong>kai krypton ho ou gnōsthēsetai</strong> — and hidden what will not be known — the passive futures (<em>apokalyphthēsetai</em>, <em>gnōsthēsetai</em>) are divine passives: God is the one who will disclose and make known. The eschatological disclosure renders all present concealment temporary.</p>',
    "3": '<p><strong>anth hōn hosa en tē skotia eipate en tō phōti akousthēsetai</strong> — therefore what you have said in the dark will be heard in the light — the spatial metaphors (dark/light) and acoustic metaphors (whispered/proclaimed) illustrate the principle of v.2. <em>En tois tameious</em> (in the inner rooms, store-rooms — private chambers without windows) — the most private location imaginable. <strong>kai ho pros to ous elalesate en tois tameois kērychthēsetai epi tōn dōmatōn</strong> — what you whispered in the ear in the inner rooms will be proclaimed on the rooftops — the flat Palestinian rooftop was the public announcement platform; the herald\'s position. What was whispered privately will be heralded publicly — the complete reversal of secrecy.</p>',
    "4": '<p><strong>Legō de hymin tois philois mou</strong> — I say to you, my friends — <em>philois</em> (friends — a term of close relational warmth, used by Jesus for the disciples in John 15:13-15) personalizes the following command. <strong>Mē phobēthēte apo tōn apokteinontōn to sōma kai meta tauta mē echontōn perissoteron ti poiēsai</strong> — do not fear those who kill the body and after that have nothing more they can do — the limit of human violence is the body; death exhausts the persecutor\'s power. The grammar is emphatic: <em>mē echontōn perissoteron ti poiēsai</em> (having nothing more, nothing exceeding, to do) — after death, their power is spent.</p>',
    "5": '<p><strong>hypo deixō de hymin tina phobēthēte</strong> — but I will show you whom to fear — the contrast is sharp: the one to fear is not the executioner but the Judge. <strong>phobēthēte ton meta to apokteinai echonta exousian embalein eis tēn geennan</strong> — fear the one who after killing has authority to throw into Gehenna — <em>geenna</em> is the Greek form of <em>Ge-Hinnom</em> (Valley of Hinnom), the ravine south of Jerusalem where child sacrifice occurred (Jer 7:31; 2 Chr 28:3; 33:6) and later became the city\'s refuse dump; in Second Temple Jewish thought it became the metaphor for final divine judgment. <em>Exousia embalein eis tēn geennan</em> — authority to throw into Gehenna — the one who has this post-mortem authority is God. <strong>nai, legō hymin, touton phobēthēte</strong> — yes, I tell you, fear this one.</p>',
    "6": '<p><strong>Ouchi pente strouthia pōlountai assariōn dyo</strong> — are not five sparrows sold for two assaria? — <em>strouthion</em> (sparrow — the cheapest available bird in the market; Mt 10:29 gives two for one assarion, but Luke\'s five for two assaria is a bulk-discount pricing: buy two get one free). <em>Assarion</em> is a small copper Roman coin, 1/16 of a denarius — the bare minimum of purchasing power. <strong>kai hen ex autōn ouk estin epilelēsmemon enōpion tou theou</strong> — yet not one of them is forgotten before God — <em>epilanthanō</em> (to forget, overlook — perfect passive: has been and remains forgotten) with the negation: God\'s attention to the sparrow is permanent and complete. The argument is a fortiori: if God holds sparrows in continuous awareness, how much more his human image-bearers.</p>',
    "7": '<p><strong>alla kai hai triches tēs kephalēs hymōn pasai ērithmēntai</strong> — but even the hairs of your head are all numbered — <em>ērithmēntai</em> (perfect passive: have been numbered and remain counted) — not merely that God could count them but that they are presently enumerated. The hyperbolic precision (the most individually variable and untracked aspect of a person\'s body) illustrates total divine knowledge of particulars. <strong>mē phobou; pollōn strouthiōn diapherete</strong> — do not fear; you are worth more than many sparrows — <em>diapherō</em> (to differ from, be worth more than, surpass in value) grounds the reassurance in comparative worth, not in absence of danger.</p>',
    "8": '<p><strong>Legō de hymin, pas hos an homologēsē en emoi emprosthen tōn anthrōpōn</strong> — I say to you, everyone who confesses in me before men — <em>homologeō en emoi</em> (to confess in me, acknowledge publicly — the <em>en</em> construction is unusual: "in me" implies confessing from within union with Jesus, not merely about him) is the public acknowledgment in hostile circumstances. <strong>kai ho huios tou anthrōpou homologēsei en autō emprosthen tōn aggelōn tou theou</strong> — the Son of Man will also confess in him before the angels of God — the eschatological endorsement is symmetrical: present confession in Jesus → future acknowledgment by the Son of Man before God\'s heavenly court. The angels are the divine council witnesses.</p>',
    "9": '<p><strong>ho de arnēsamenos me enōpion tōn anthrōpōn aparnēthēsetai enōpion tōn aggelōn tou theou</strong> — the one who denies me before men will be denied before the angels of God — <em>arneomai</em> (to deny, disown) and the intensified <em>aparneomai</em> (to deny thoroughly, disown completely) create an asymmetry: the human denial is simple; the divine denial is emphatic. The passive <em>aparnēthēsetai</em> (will be denied) is divine passive: God/the Son of Man will do the denying. The courtroom imagery (before men/before the angels) structures the parallel.</p>',
    "10": '<p><strong>kai pas hos erei logon eis ton huion tou anthrōpou, aphethēsetai autō</strong> — everyone who speaks a word against the Son of Man, it will be forgiven him — the contrast is theologically precise: speaking against the Son of Man (his earthly form, his human vulnerability, his apparent weakness) is forgivable — the disciples\' failure of nerve during the Passion is included in this. <strong>tō de eis to hagion pneuma blasphēmēsanti ouk aphethēsetai</strong> — but to the one who blasphemes against the Holy Spirit it will not be forgiven — <em>blasphēmia kata tou pneumatos</em> is the deliberate, persistent rejection of the Spirit\'s testimony about Jesus; in context (cf. Mk 3:22-30) it is attributing the Spirit\'s works to demonic agency. It is the sin of hardened finality, not a momentary lapse.</p>',
    "11": '<p><strong>Hotan de eispherōsin hymas epi tas synagōgas kai tas archas kai tas exousias</strong> — when they bring you before synagogues and rulers and authorities — the threefold escalation: <em>synagōgai</em> (Jewish community courts), <em>archai</em> (magistrates, principalities — civic officials), <em>exousiai</em> (powers, authorities — Roman imperial power). The progression mirrors Acts: Stephen before the Sanhedrin (Acts 6-7), Paul before Jewish synagogues, then Roman proconsuls, then kings. <strong>mē merimnēsēte pōs ē ti apologēsēsthe ē ti eipēte</strong> — do not be anxious about how or what you should say in defense — <em>apologeomai</em> (to make a defense, give an apologia) is the legal defense speech; the disciples are not to prepare it in advance.</p>',
    "12": '<p><strong>to gar hagion pneuma didaxei hymas en autē tē hōra ha dei eipein</strong> — for the Holy Spirit will teach you in that very hour what it is necessary to say — <em>to hagion pneuma</em> is the promised advocate (cf. Jn 14:26 where the Paraclete teaches); the Spirit\'s role in legal defense before authorities is fulfilled in Acts 4:8 (Peter, filled with the Holy Spirit, addressing the Sanhedrin), Acts 6:10 (Stephen\'s opponents unable to withstand his Spirit-given wisdom), Acts 13:9 (Paul filled with the Spirit rebuking Elymas). <em>En autē tē hōra</em> (in that very hour) — the provision is contemporaneous with the need, not advance preparation.</p>',
    "13": '<p><strong>Eipen de tis ek tou ochlou autō, Didaskale, eipe tō adelphō mou merisasthai met emou tēn klēronomian</strong> — someone from the crowd said to him: Teacher, tell my brother to divide the inheritance with me — the interruption is abrupt and jarring after the teaching on persecution and the Spirit. The petition is a property dispute about inheritance (<em>klēronomia</em>), the division of an estate. Jewish inheritance law was complex; the firstborn received a double share (Deut 21:17); disputes required a recognized authority. The man addresses Jesus as <em>Didaskalos</em> (Teacher), expecting him to function as a rabbinic arbitrator.</p>',
    "14": '<p><strong>ho de eipen autō, Anthrōpe, tis me katestēsen kritēn ē meristēn eph hymas</strong> — he said to him: Man, who appointed me a judge or a divider over you? — <em>kritēs</em> (judge) and <em>meristēs</em> (divider, arbitrator — unique to this passage in the NT) are the roles Jesus declines. The refusal is not indifference to justice but a redirection: the rabbinic arbitration role is not his commission. The echo of Moses\'s refusal to be a judge in Exod 2:14 is deliberate; Jesus will not be drawn into property adjudication. His question implies that no one has made him their judge — a comment on the nature of his authority.</p>',
    "15": '<p><strong>Eipev de pros autous, Horate kai phylassesthe apo pasēs pleonexias</strong> — he said to them: See and guard yourselves from all covetousness/greed — <em>pleonexia</em> (greediness, the desire for more, covetousness) is listed by Paul among the fundamental vices (Col 3:5; Eph 5:3) and identified with idolatry (Col 3:5). <strong>hoti ouk en tō perisseuein tini hē zōē autou estin ek tōn hyparchontōn autou</strong> — because life does not consist for anyone in the abundance of his possessions — <em>perisseuo</em> (to abound, overflow, be in excess) and <em>hyparchonta</em> (possessions, property — literally "what one already has, what lies beneath") define the equation the crowd assumes: more possessions = more life. Jesus denies the equation categorically.</p>',
    "16": '<p><strong>Eipen de parabolēn pros autous legōn</strong> — he spoke a parable to them saying — the parable of the Rich Fool is unique to Luke and serves as the narrative illustration of v.15\'s principle. <strong>Anthrōpou tinos plousiou euphorēsen hē chōra</strong> — a certain rich man\'s land yielded abundantly — <em>euphoreo</em> (to bear well, produce abundantly — a hapax in the NT) is the agricultural term for an exceptional harvest. The man is already rich (<em>plousios</em>); the abundant harvest is surplus beyond surplus. The problem the parable addresses is the management of unexpected abundance.</p>',
    "17": '<p><strong>kai dielogizeto en heautō legōn, Ti poiēsō, hoti ouk echō pou synaxō tous karpous mou</strong> — and he was deliberating within himself saying: what shall I do? for I have nowhere to store my crops — the internal deliberation (<em>dielogizeto en heautō</em>) reveals a man who consults no one — not God, not community, not the poor. The question "what shall I do?" (Ti poiēsō) is answered entirely in terms of storage expansion; no possibility of distribution occurs to him. <em>Synaxō tous karpous mou</em> (gather my crops) — the possessive pronoun <em>mou</em> (my) appears five times in vv.17-19 as the self-referential grammar of covetousness.</p>',
    "18": '<p><strong>kai eipen, Touto poiēsō</strong> — and he said: this is what I will do — the decision is immediate and self-generated. <strong>kathelō mou tas apothēkas kai meizōnas oikodomēsō</strong> — I will pull down my barns and build larger ones — <em>apothēkē</em> (storehouse, barn, granary — literally a place to put things away) is the storage facility that determines the scope of the man\'s imagination. Bigger storage = more retained wealth = greater security. The solution to surplus is more capacity for accumulation. <strong>kai synaxō ekei panta ton siton kai ta agatha mou</strong> — and I will gather there all my grain and all my goods — <em>ta agatha mou</em> (my good things) is the Epicurean vocabulary of the pleasant life.</p>',
    "19": '<p><strong>kai erō tē psychē mou, Psychē, echeis polla agatha keimena eis etē polla</strong> — and I will say to my soul: Soul, you have many good things laid up for many years — the self-address to <em>psychē</em> (soul, life-force, self) treats the soul as an entity to be managed and satisfied through material provision. <em>Keimena eis etē polla</em> (laid up for many years) — the projected time-horizon of the stored goods determines the man\'s sense of security. <strong>anapauou, phage, pie, euphrainou</strong> — rest, eat, drink, be merry — the four imperatives of Epicurean <em>ataraxia</em> (tranquility): withdrawal from striving into enjoyment of accumulated goods. The formula echoes Eccles 8:15; the man has made Qohelet\'s resignation into his life plan.</p>',
    "20": '<p><strong>eipen de autō ho Theos, Aphrōn, tautē tē nykti tēn psychēn sou apaitousin apo sou</strong> — God said to him: Fool, this very night they demand your soul back from you — <em>Aphrōn</em> (fool — one who lacks practical wisdom and moral discernment, not merely unintelligent; cf. Ps 14:1 "the fool says in his heart, There is no God") is God\'s one-word verdict on the life-plan. <em>Apaitousin</em> (they demand back — present tense: even now demanding; plural subject is the Semitic idiom for impersonal divine action, "one demands of you") is the creditor language of reclaiming a loan: the soul was never the man\'s property. <strong>ha de hētoimasas, tini estai</strong> — what you prepared, whose will it be? — the question the man never asked while preparing.</p>',
    "21": '<p><strong>houtōs ho thēsaurizōn heautō kai mē eis theon ploutōn</strong> — so it is with the one treasuring for himself and not being rich toward God — <em>thēsaurizō heautō</em> (treasuring up for oneself) is the hoarding grammar, contrasted with <em>eis theon ploutōn</em> (being rich toward God — a unique Lukan phrase). The preposition <em>eis</em> (toward, into) with <em>theon</em> defines the direction of wealth: toward God means used generously according to divine priorities (cf. 12:33; 16:9; 18:22; 21:1-4). The parable does not condemn wealth but the direction of accumulation: self-ward vs. God-ward.</p>',
    "22": '<p><strong>Eipen de pros tous mathētas autou</strong> — he said to his disciples — the audience shifts back to disciples (from the crowd\'s parable, vv.13-21). <strong>Dia touto legō hymin, mē merimnate tē psychē hymon ti phagēte, mēde tō sōmati hymon ti endysēsthe</strong> — therefore I say to you, do not be anxious about your life what you will eat, nor about your body what you will wear — <em>merimnō</em> (to be anxious, divided in mind — from <em>merizō</em> to divide; anxiety as a mind divided against itself by competing concerns) is the subject of the following argument. The body-soul pair (food for the soul/clothes for the body) sets the two axes of survival anxiety.</p>',
    "23": '<p><strong>hē gar psychē pleion estin tēs trophēs kai to sōma tou endymatos</strong> — for the soul/life is more than food and the body more than clothing — the argument from greater to lesser: if God gave the greater (life itself, the body), is he not also capable of supplying the lesser (food, clothing)? The priorities of divine provision are established by the greater gift; the creator-giver of life is not indifferent to its sustenance. The verse is the logical premise for all of vv.24-31.</p>',
    "24": '<p><strong>katanoeate tous korakas, hoti ou speirousin oude therizousin</strong> — consider the ravens, because they do not sow or reap — <em>katanoeō</em> (to perceive thoroughly, observe carefully, contemplate — a stronger word than simply "look") indicates sustained reflective attention to the natural object as a theological text. Luke uses ravens (<em>korax</em>) where Matthew has "birds of the air" (Mt 6:26); ravens are ritually impure (Lev 11:15) and therefore an unexpected illustration of divine care — God feeds even the unclean birds. <strong>hois ouk estin tameion oude apothēkē, kai ho Theos trephei autous</strong> — who have no storeroom or barn, and God feeds them — the ravens have none of the storage infrastructure the rich fool built; their lack of storage is precisely what illustrates trust in direct divine provision.</p>',
    "25": '<p><strong>tis de ex hymōn merimnōn dynatai epi tēn hēlikian autou prostheinai pēchyn</strong> — which of you by being anxious can add a cubit to his lifespan? — <em>hēlikia</em> (stature, age, lifespan — ambiguous between physical height and duration of life; in context "lifespan" fits better) is what anxiety cannot extend. <em>Pēchys</em> (cubit — a unit of length, ~45cm) applied to lifespan is the metaphor of a very small addition to what is already given. The rhetorical question expects "none of you"; anxiety is not merely useless but specifically powerless over the things it fears most.</p>',
    "26": '<p><strong>ei oun oude elachiston dynasthe, ti peri tōn loipōn merimnate</strong> — if therefore you cannot even do the least, why are you anxious about the rest? — the argument from inability: anxiety fails even at the smallest extension of life; how then can it address the larger provision questions? <em>Elachiston</em> (the least, the smallest) — adding a cubit to one\'s height/lifespan is described as the "least" concern; the rhetorical point is that anxiety is impotent even at the minimum level of its aspirations. The conclusion is that anxiety achieves nothing and therefore ought not to replace trust.</p>',
    "27": '<p><strong>katanoeisate ta krina pōs auxanei, ou kopia oude nēthei</strong> — consider how the lilies grow; they do not toil or spin — <em>krina</em> (lilies — probably the anemone or other wildflowers of the Galilean hillsides, not specifically water-lilies). The double negative: no agricultural labor (<em>kopiaō</em> = to toil, labor wearily) and no textile production (<em>nēthō</em> = to spin thread). <strong>legō de hymin, oud Solomōn en pasē tē doxē autou periebaleto hōs hen toutōn</strong> — I tell you, not even Solomon in all his glory was clothed like one of these — Solomon at the height of imperial wealth (1 Kgs 10) cannot match the wildflower\'s clothing; the comparison makes divine provision appear more lavish than human achievement.</p>',
    "28": '<p><strong>ei de en agrō ton chorton onta sēmeron kai aurion eis klibanon ballomenon ho Theos houtōs amphiazei</strong> — if God so clothes the grass that is in the field today and tomorrow is thrown into the oven — <em>klibanon</em> (clay oven — dried grass and thorns were used as fuel for baking ovens in Palestinian villages; grass is literally a disposable fuel). The argument runs from inferior to superior: grass is temporary fuel; yet God clothes it lavishly. Disciples are permanent image-bearers. <strong>posō mallon hymas, oligopistoi</strong> — how much more you, O you of little faith — <em>oligopistoi</em> (little-faiths — a Matthean word; Luke uses it only here) gently rebukes anxious disciples as those who trust too little.</p>',
    "29": '<p><strong>kai hymeis mē zēteite ti phagēte kai ti piēte kai mē meteorrizesthe</strong> — do not seek what you will eat and what you will drink, and do not be anxious/suspended — <em>meteōrizō</em> (to suspend in mid-air, to be in suspense, to be unsettled — a hapax in the NT, from <em>meteōros</em> = lifted up, suspended; used of ships tossed at sea or minds suspended in uncertainty) gives the specific texture of food-and-drink anxiety: an unsettled, floating mental state that cannot rest. The instruction is not against planning but against the anxious suspension that makes provision the center of one\'s existence.</p>',
    "30": '<p><strong>tauta gar panta ta ethnē tou kosmou epizētousin</strong> — for all these things the nations/Gentiles of the world seek after — <em>ta ethnē</em> (the nations, the Gentiles — those without covenant relationship with YHWH) are defined by their preoccupation with food and drink: survival anxiety as the organizing principle of life without God. <strong>hymōn de ho patēr oiden hoti chrēzete toutōn</strong> — but your Father knows that you need these things — the counter to Gentile anxiety: the disciples\' Father (<em>ho patēr</em> — the intimate address presupposing covenant relationship) already knows the need. Prior divine knowledge removes the anxious need to secure what is already known and provided for.</p>',
    "31": '<p><strong>plēn zēteite tēn basileian autou, kai tauta prostethēsetai hymin</strong> — but seek his kingdom, and these things will be added to you — <em>plēn</em> (but, however — Luke\'s adversative pivot) redirects from anxious material-seeking to kingdom-seeking. <em>Zēteite tēn basileian</em> (seek the kingdom) is the single positive command; everything else is addition to it. <em>Prostethēsetai</em> (will be added, divine passive — God will add) promises material provision as the byproduct of kingdom-priority. The economy of the kingdom reverses the economy of anxiety: seek what is primary, receive what is secondary as gift.</p>',
    "32": '<p><strong>Mē phobou, to mikron poimnion, hoti eudokēsen ho patēr hymōn dounai hymin tēn basileian</strong> — do not fear, little flock, for your Father has been pleased to give you the kingdom — <em>to mikron poimnion</em> (the little flock) is the only occurrence of "flock" applied to the disciples in Luke; it combines smallness with pastoral intimacy. Against the world\'s great powers and institutions, the disciples are a small and vulnerable group. <em>Eudokēsen</em> (was pleased, delighted to — aorist: a completed decision expressing the Father\'s sovereign pleasure) grounds the gift of the kingdom in divine initiative and delight, not in the disciples\' worthiness or size. The past tense ("was pleased") indicates a settled divine commitment.</p>',
    "33": '<p><strong>Pōlēsate ta hyparchonta hymōn kai dote eleēmosynēn</strong> — sell your possessions and give alms — the instruction is radical and concrete: the anxiety about possessions is resolved not by securing more but by releasing what one has. <em>Eleēmosynē</em> (almsgiving, merciful giving — from <em>eleos</em>, mercy) is the covenantal obligation of those in community with the needy. <strong>Poiēsate heautois ballantia mē palaiomena, thēsauron anekleipton en tois ouranois</strong> — make for yourselves purses that do not wear out, an inexhaustible treasure in the heavens — <em>ballantion mē palaioumenon</em> (purse that does not grow old, deteriorate) contrasts with earthly containers that rot, rust, or are stolen. The heavenly treasure is <em>anekleiptos</em> (inexhaustible — unique to this passage in the NT).</p>',
    "34": '<p><strong>hopou gar estin ho thēsauros hymōn, ekei kai hē kardia hymōn estai</strong> — for where your treasure is, there also will be your heart — <em>kardia</em> (heart — in Hebrew anthropology, the center of will, desire, and decision-making, not merely emotion) follows the location of the treasure: the heart is attracted to what it values most, and values what it attends to. The aphorism runs in both directions: where you place your treasure determines the location of your heart; and where your heart already is reveals where your true treasure lies. Almsgiving (v.33) redirects the treasure and thereby reshapes the heart\'s orientation.</p>',
    "35": '<p><strong>Estōsan hymōn hai osphyes periezōsmenai kai hoi lychnoi kaiomenoi</strong> — let your loins be girded and your lamps burning — <em>osphyes periezōsmenai</em> (loins girded) is the Exodus posture: Israel ate the Passover "with your belt fastened" (<em>mizrayin</em>, Exod 12:11 LXX — girded loins), ready to depart at any moment. <em>Lychnoi kaiomenoi</em> (lamps burning) — the continuous burning lamp signals active readiness through the dark hours; the unprepared lamp means one will be caught in darkness. The two images combine: body ready for action, light for the journey.</p>',
    "36": '<p><strong>kai hymeis homoioi anthrōpois prosdechomenois ton kyrion heautōn</strong> — and you like men waiting for their lord — <em>prosdechomai</em> (to wait for, expect with readiness — active expectation, not passive waiting) characterizes the servant\'s posture. <strong>hotan anastasē ek tōn gamōn, hina elthontos kai krousantos eutheōs anoixōsin autō</strong> — when he returns from the wedding banquet, so that when he comes and knocks they may open to him immediately — <em>gamoi</em> (wedding celebrations — plural, the extended festivities lasting multiple days in the ancient world; the return time is genuinely uncertain). <em>Eutheōs anoixōsin</em> (they immediately open) — no delay when the expected lord arrives; instant response marks the ready servant.</p>',
    "37": '<p><strong>makarioi hoi douloi ekeinoi, hous elthōn ho kyrios heurēsei grēgorountas</strong> — blessed are those servants whom the lord, coming, will find watching — <em>grēgoreō</em> (to stay awake, keep watch — from <em>egeirō</em>: to wake up) is the New Testament\'s eschatological alertness word (cf. Mt 24:42-43; 1 Thess 5:6; Rev 3:3; 16:15). The <em>makarios</em> (blessed) is the beatitude form, declaring the eschatological status of those found in readiness. <strong>amēn legō hymin hoti perizōsetai kai anaklinei autous kai parelthōn diakonēsei autois</strong> — truly I tell you he will gird himself and seat them and coming to them he will serve them — the role-reversal is astonishing: the returning Lord serves his faithful servants at table.</p>',
    "38": '<p><strong>kan en tē deutera kan en tē tritē phylakē elthē kai heurē houtōs, makarioi eisin ekeinoi</strong> — even if he comes in the second or in the third watch and finds them so, blessed are those — the night watches: Roman military custom divided the night into four 3-hour watches (6-9pm, 9-midnight, midnight-3am, 3-6am); Jewish custom used three watches. The second and third watches (midnight through the early morning hours) are the most demanding times to maintain alertness. The blessing extends to those found watching at the most inconvenient hours of waiting — a comment on the cost and honor of prolonged eschatological readiness.</p>',
    "39": '<p><strong>touto de ginōskete, hoti ei ēdei ho oikodespotēs poia hōra ho kleptēs erchetai</strong> — but know this: if the householder had known at what hour the thief was coming — <em>oikodespotēs</em> (master of the house, householder — compound of <em>oikos</em> house and <em>despotēs</em> master) is the responsible guardian of the household. The thief analogy introduces a different aspect of the Lord\'s coming: not the welcomed master-servant relationship of vv.36-38 but the unpredictability of the timing. <strong>ouk aphēken diorychthēnai ton oikon autou</strong> — he would not have allowed his house to be broken into — <em>dioryssō</em> (to dig through — burglars in ancient Palestine dug through mud-brick walls rather than breaking in through doors).</p>',
    "40": '<p><strong>kai hymeis ginesthe hētoimoi, hoti hē hōra ou dokeite ho huios tou anthrōpou erchetai</strong> — and you must be ready, because the Son of Man is coming at an hour you do not expect — <em>ginesthe hētoimoi</em> (become ready, be ready — present imperative: continuous readiness) is the practical conclusion from both the servant-parable (vv.35-38) and the thief-analogy (v.39). <em>Hē hōra ou dokeite</em> (the hour you do not expect, do not think) — the timing\'s unexpectedness is the consistent point; readiness cannot be contingent on predicted timing. <em>Ho huios tou anthrōpou erchetai</em> — the Son of Man comes (present tense in Greek, conveying imminent certainty).</p>',
    "41": '<p><strong>Eipen de ho Petros, Kyrie, pros hēmas tēn parabolēn tautēn legeis ē kai pros pantas</strong> — Peter said: Lord, are you telling this parable to us or to everyone? — Peter\'s question is characteristically practical and boundary-setting: is this demand for readiness directed specifically to the apostolic circle or to the entire crowd? The address <em>Kyrie</em> (Lord) marks the heightened awareness of the teaching\'s seriousness. Jesus does not answer Peter\'s question directly but deepens and expands the image, implicitly directing the heightened responsibility to those in leadership positions.</p>',
    "42": '<p><strong>kai eipen ho Kyrios, Tis ara estin ho pistos oikonomos ho phronimos</strong> — the Lord said: who then is the faithful and wise manager? — <em>oikonomos</em> (estate manager, steward — responsible for managing the master\'s household and distributing provisions to servants; a position of delegated authority and accountability) is the image Luke uses for responsible leadership. <em>Pistos</em> (faithful, trustworthy) and <em>phronimos</em> (wise, prudent, practically discerning) are the two qualities the master values. <strong>hon katastēsei ho kyrios epi tēs therapeias autou tou didonai en kairō to sitometrion</strong> — whom the lord will put in charge of his household staff to give them their food allowance in due time — <em>sitometrion</em> (grain-ration, food-allowance) is the regular provision the steward distributes.</p>',
    "43": '<p><strong>makarios ho doulos ekeinos, hon elthōn ho kyrios autou heurēsei poiounta houtōs</strong> — blessed is that servant whom his lord coming will find doing so — the beatitude here is not for passive waiting but for active faithful service: the manager found distributing the household\'s food on schedule. The eschatological arrival finds the servant in the middle of ordinary faithful work — not in a posture of dramatic preparation but in the rhythm of daily responsibility. This is the Lukan theology of faithful stewardship: eschatological readiness looks like continued doing of one\'s assigned work.</p>',
    "44": '<p><strong>alēthōs legō hymin hoti epi pasin tois hyparchousin autou katastēsei auton</strong> — truly I tell you he will put him in charge of all his possessions — the reward for faithful stewardship of limited responsibility is expanded responsibility. The pattern mirrors the Parable of the Pounds (19:11-27): faithful management of a portion leads to superintendence of all. <em>Epi pasin tois hyparchousin autou</em> (over all his possessions) is the maximum delegation the master can grant; the faithful servant becomes the master\'s full proxy. In the Lukan community context, this addressed leaders of house-churches and the post-resurrection mission.</p>',
    "45": '<p><strong>ean de eipē ho doulos ekeinos en tē kardia autou, Chronizei ho kyrios mou erchesthai</strong> — but if that servant says in his heart: my lord is delayed in coming — the servant\'s inner reasoning (in the heart = a private decision, not announced) that the master\'s delay is permanent creates the occasion for abuse. <em>Chronizei</em> (is delayed, is taking long) — the assumption that the delay will continue indefinitely is the theological error that liberates bad behavior. <strong>kai arxētai typtein tous paidas kai tas paidikas esthiein te kai pinein kai methyskesthai</strong> — and begins to beat the male and female servants and to eat and drink and get drunk — the three abuses: violence against subordinates, self-indulgence, and excess.</p>',
    "46": '<p><strong>hēxei ho kyrios tou doulou ekeinou en hēmera hē ou prosdokā kai en hōra hē ou ginōskei</strong> — the lord of that servant will come on a day he does not expect and at an hour he does not know — the timing certainty is not disclosed but the surprise is certain. <strong>kai dichotomēsei auton kai to meros autou meta tōn apistōn thēsei</strong> — and he will cut him in two and put his portion with the unfaithful — <em>dichotomeo</em> (to cut in two, bisect — a severe and graphic punishment term; perhaps a legal idiom for severe flogging or for dismissal with permanent separation from the household) is the most extreme consequence in the parable. <em>Meta tōn apistōn</em> (with the unbelievers, the faithless) is the final category: the unfaithful servant is reclassified as a non-disciple.</p>',
    "47": '<p><strong>ekeinos de ho doulos ho gnous to thelēma tou kyriou autou kai mē hetoimasas ē poiēsas pros to thelēma autou darthēsetai pollas</strong> — that servant who knew his master\'s will and did not prepare or act according to his will will be beaten with many blows — the principle of proportionate accountability: knowledge of the master\'s will creates proportionate responsibility. <em>Darthēsetai pollas</em> (will be beaten with many — scourged many times; <em>dairō</em> = to flay, beat) — the punishment calibrated to knowledge. The implication for teachers and religious leaders who "know" the scriptures is direct: their accountability is heightened by their knowledge.</p>',
    "48": '<p><strong>ho de mē gnous, poiēsas de axia plēgōn, darthēsetai oligas</strong> — the one who did not know, and did things worthy of punishment, will be beaten with few — the ignorant wrongdoer is punished less severely because knowledge is the multiplier of accountability. <strong>panti de hō edothē poly, poly zētēthēsetai par autou</strong> — from everyone to whom much was given, much will be required of him — the programmatic statement of stewardship theology: gift creates obligation; scale of gift determines scale of responsibility. <strong>kai hō parethento poly, perissoteron aitēsousin auton</strong> — and to whom they entrusted much, they will ask all the more of him — the plural subject ("they will ask") is the Semitic impersonal divine passive for God\'s accounting.</p>',
    "49": '<p><strong>Pyr ēlthon balein epi tēn gēn, kai ti thelō ei ēdē anēphthē</strong> — I came to cast fire on the earth, and how I wish it were already kindled! — <em>pyr balein epi tēn gēn</em> (to cast fire on the earth) is the eschatological fire of divine purification: Isa 66:15-16 (YHWH coming with fire to judge), Joel 2:30-31 (fire as sign of the day of the LORD), Mal 3:2-3 (the Messenger like a refiner\'s fire). The longing expressed (<em>ti thelō ei ēdē anēphthē</em> — what I wish, if only it were already kindled!) is Jesus\'s desire for the completion of his mission: the eschatological fire will not come without the cross. The saying stands as the strongest expression of Jesus\'s emotional longing for the fulfillment of his work.</p>',
    "50": '<p><strong>baptisma de echō baptisthēnai, kai pōs synechomai heōs hotou telesthē</strong> — but I have a baptism to be baptized with, and how constrained I am until it is completed! — <em>baptisma ... baptisthēnai</em> (a baptism to be baptized with) is the metaphorical use of immersion for overwhelming experience, specifically death: being plunged into suffering and death as into deep water (cf. Ps 42:7; 69:1-2; Isa 43:2 "when you pass through the waters"). <em>Synechomai</em> (I am constrained, hemmed in, pressed — from <em>synechō</em>: to hold together under pressure; Luke uses it for illness\'s grip in 4:38 and fever\'s constraint) expresses the pressing weight of the approaching Passion. <em>Heōs hotou telesthē</em> (until it is completed/accomplished — <em>teleō</em>: brought to its appointed end) — the same root as "it is finished" (Jn 19:30).</p>',
    "51": '<p><strong>Dokeite hoti eirēnēn paregenomēn dounai en tē gē</strong> — do you think I came to give peace on earth? — the question confronts the assumption of a peaceful Messianic program. The OT <em>shalom</em> (peace, wholeness) promised for the messianic age (Isa 9:6-7; Mic 5:5; Zech 9:10) might lead to the expectation of social harmony. <strong>ouchi, legō hymin, all ē diamerismon</strong> — no, I tell you, but rather division — <em>diamerismos</em> (division, splitting apart — from <em>diamerizō</em>: to divide through, distribute) is not Jesus\'s purpose but his effect: the proclamation of the kingdom divides those who receive from those who reject, and that division runs through families (v.52-53).</p>',
    "52": '<p><strong>esontai gar apo tou nyn pente en heni oikō diamemerismenoi</strong> — for from now on there will be five in one household divided — <em>apo tou nyn</em> (from now on) is the Lukan present-eschatological marker for the new era Jesus\'s ministry inaugurates (cf. 1:48; 5:10; 22:18,69). <strong>treis epi dysin kai dyo epi trisin</strong> — three against two and two against three — the odd numbers create the impossibility of a stable majority within the family unit: no side can win or absorb the other. The household, the basic unit of ancient Mediterranean social stability, is fractured by the advent of Jesus.</p>',
    "53": '<p><strong>diamerithesuontai patēr epi huiō kai huios epi patri</strong> — father against son and son against father — the family division follows generational lines with the possibility of the division running in either direction: parent may reject child who follows Jesus, or child may reject parent who does. The pairs: father/son, mother/daughter, mother-in-law/daughter-in-law cover both genders and both directions of the adult family relationships. The language echoes Mic 7:6 (a man\'s enemies are the members of his own household), applied to the prophetic mission and now fulfilled in Jesus\'s ministry.</p>',
    "54": '<p><strong>Elegen de kai tois ochlois</strong> — he was saying also to the crowds — the audience shift from disciples (vv.22, 35, 41) back to the crowds; the following sayings are directed at the broader public. <strong>Hotan idēte tēn nephalēn anatellousari apo dysmōn, eutheōs legete hoti Ombros erchetai</strong> — when you see a cloud rising from the west, immediately you say: a shower is coming — the Mediterranean weather pattern: clouds from the west brought rain off the sea; south wind brought desert heat. The crowd\'s meteorological competence is established as the baseline for the comparison.</p>',
    "55": '<p><strong>kai hotan noton pneonta, legete hoti Kauson estai, kai ginetai</strong> — and when the south wind blows, you say: it will be scorching, and it is — <em>notos</em> (the south wind — from the Negev and Arabian desert, bringing hot dry air; the <em>hamsin</em> or <em>sirocco</em>) reliably produces high temperatures. The twice-confirmed accuracy of the crowd\'s weather reading establishes that they are capable of interpreting natural signs correctly.</p>',
    "56": '<p><strong>Hypokritai, to prosōpon tēs gēs kai tou ouranou oidate dokimazein, ton kairon de touton pōs ouk oidate dokimazein</strong> — Hypocrites! You know how to interpret the face of the earth and the sky; how is it you do not know how to interpret this present time? — <em>Hypokritai</em> (Hypocrites — actors playing a role; here those who perform meteorological competence while refusing the harder discernment of the present moment) is the accusation. <em>Ton kairon de touton</em> (this present time — <em>kairos</em>, the opportune, significant moment, not just chronological time) is the time of the Messiah\'s presence, the year of the Lord\'s favor (4:19). Reading weather requires no moral commitment; reading the <em>kairos</em> requires decision.</p>',
    "57": '<p><strong>Ti de kai aph heautōn ou krinete to dikaion</strong> — why do you not also judge from yourselves what is right? — the capacity for just judgment (<em>to dikaion</em>, the just/right thing) is presented as available within the audience: they have sufficient moral perception to discern the right course without external compulsion. The question implies that the failure to read the times (v.56) is a failure of moral will, not of intellectual capacity. <em>Aph heautōn</em> (from yourselves, on your own initiative) — independent moral discernment is not only possible but expected.</p>',
    "58": '<p><strong>hōs gar hypageis meta tou antidikou sou ep archonta, en tē hodō dos ergasian apēlachthai ap autou</strong> — for as you are going with your adversary before the magistrate, on the way make every effort to be released from him — <em>antidikos</em> (adversary in a lawsuit — literally "one who works against you in court") and <em>archōn</em> (ruler, magistrate) set the legal context. <em>Dos ergasian</em> (give effort, apply energy — an idiomatic phrase for "make every effort") before reaching the court. <strong>mēpote katasyrē se pros ton kritēn kai ho kritēs se paradōsei tō praktori</strong> — lest he drag you to the judge and the judge deliver you to the collector — <em>praktōr</em> (debt-collector, enforcement officer — a Lukan hapax) who enforces payment.</p>',
    "59": '<p><strong>legō soi, ou mē exelthēs ekeithen heōs kai to eschaton lepton apodōs</strong> — I tell you, you will not get out from there until you pay the last lepton — <em>lepton</em> (the smallest Jewish copper coin, worth 1/2 of a Roman quadrans — the "widow\'s mite" of 21:2) specifies the minimum unit of debt. <em>Ou mē exelthēs</em> (you will certainly not get out — double negative for emphatic certainty) is the final word of warning. Whether the parable is purely wisdom-instruction about legal prudence or an allegory of eschatological urgency (settle with God before the judgment) is left open; Luke\'s placement after the kairos-interpretation saying (vv.56-57) supports the latter reading.</p>',
  },
  "13": {
    "1": '<p><strong>parēsan de tines en autō tō kairō apangellontes autō peri tōn Galilaion</strong> — some were present at that very time reporting to him about the Galileans — <em>en autō tō kairō</em> (at that very time — the <em>kairos</em> of 12:56, the opportune time of the Messiah\'s presence) links this scene to the preceding. The report concerns Galileans whose blood Pilate had mixed with their sacrifices (<em>ta thymata autōn</em> = their sacrificial animals) — a brutal act of political repression during a temple sacrifice, probably in the Passover context. Pilate had history of violent suppression (cf. Josephus, Ant. 18.60-62, the aqueduct riot).</p>',
    "2": '<p><strong>kai apokritheis eipen autois, Dokeite hoti hoi Galilaioi houtoi hamartōloi para pantas tous Galilaious egenonto</strong> — answering them he said: do you think these Galileans were sinners more than all other Galileans? — the question confronts the popular theological assumption (cf. Job 4:7; John 9:2) that exceptional suffering indicates exceptional sin. The suffix <em>para pantas</em> (more than all, in comparison with all) is the specific form of the retribution-theology assumption: their worse fate implies their worse sin. Jesus rejects this interpretive framework directly.</p>',
    "3": '<p><strong>ouchi, legō hymin, all ean mē metanoēte, pantes homoiōs apoleisthe</strong> — no, I tell you, but unless you repent, you will all likewise perish — the counter-move is twofold: first, the denial of the sin-suffering equation; second, the redirection of the lesson. <em>Metanoeō</em> (to repent, change one\'s mind and direction — Luke\'s central call; cf. 5:32; 15:7,10; 16:30; 17:3,4; 24:47) is the universal requirement. <em>Pantes homoiōs apoleisthe</em> (you will all likewise perish) — the "likewise" does not predict death by Roman violence for all but perishing in the general eschatological judgment; the specific mode of the Galileans\' death illustrates the reality of human vulnerability, not the character of God\'s judgment.</p>',
    "4": '<p><strong>ē ekeinoi hoi dekaokto eph hous epesen ho pyrgos en tō Silōam kai apekteinen autous</strong> — or those eighteen on whom the tower in Siloam fell and killed them — the Tower of Siloam is otherwise unattested; the pool of Siloam (south of the City of David) was part of Hezekiah\'s water-tunnel system. A tower collapse was an accident — no human agency, no political violence. The pairing of the two incidents (Roman political violence, architectural accident) covers both categories of violent death: human malice and random disaster. <strong>dokeite hoti autoi opheiletai egenonto para pantas tous anthrōpous tous katoikountas Ierousalēm</strong> — do you think they were debtors more than all the people living in Jerusalem?</p>',
    "5": '<p><strong>ouchi, legō hymin, all ean mē metanoēte, pantes hōsautōs apoleisthe</strong> — no, I tell you, but unless you repent, you will all likewise perish — the exact same warning repeated for emphasis, now applied to the Jerusalem audience. The repetition of the call to repentance (<em>metanoēsēte</em>) grounds both cases in the same conclusion: the lesson from accidental and political deaths is not "they deserved it" but "mortality is universal and the time for repentance is now." The urgency is eschatological: <em>kairos</em> (12:56) is passing.</p>',
    "6": '<p><strong>Elegen de tautēn tēn parabolēn</strong> — he told this parable — the parable of the Barren Fig Tree follows the double repent-or-perish warning as its narrative elaboration. <strong>sykēn eichen tis en tō ampelōni autou pephuteumenēn</strong> — a man had a fig tree planted in his vineyard — the fig tree planted in a vineyard (<em>ampelōn</em>) is an unusual detail; figs were planted in vineyards (Mic 4:4; 1 Kgs 4:25) or separately. The vineyard is Israel\'s consistent OT symbol (Isa 5:1-7; Ps 80:8-16; Jer 2:21; Ezek 15); the fig tree within it represents a particular element of Israel (possibly Jerusalem or its leadership). <strong>kai ēlthen zētōn karpon en autē kai ouch heuren</strong> — and came seeking fruit on it and found none.</p>',
    "7": '<p><strong>eipen de pros ton ampelourgo, Idou tria etē aph hou erchomai zētōn karpon en tē sykē tautē kai ouch heuriskō</strong> — he said to the vinedresser: behold, three years I have been coming seeking fruit on this fig tree and finding none — <em>tria etē</em> (three years) has prompted allegorical readings (three years of Jesus\'s ministry); structurally, three attempts represents a patient but not indefinitely patient owner who has given the tree multiple seasons. <strong>ekkoson autēn; hina ti kai tēn gēn katargei</strong> — cut it down; why does it even waste the ground? — <em>katargeo</em> (to make inoperative, render useless, waste — Paul\'s favorite word for the abolition of what has served its purpose) applies to soil exhausted by an unproductive tree; the tree\'s presence prevents productive use of the land.</p>',
    "8": '<p><strong>ho de apokritheis legei autō, Kyrie, aphes autēn kai touto to etos</strong> — he answered him: Sir, leave it also this year — the vinedresser\'s intercession is the parable\'s pivot: a third party pleads for continued opportunity. <strong>heōs hotou skapsō peri autēn kai balō kopria</strong> — until I dig around it and throw manure — <em>skaptō</em> (to dig — to aerate and loosen compacted soil around the roots, allowing moisture and nutrients to penetrate) and <em>kopria</em> (dung, manure — the fertilizer that accelerates growth) are the two interventions the vinedresser will provide. The intensification of care before the final deadline: the tree will be given every possible advantage before the verdict of fruitlessness becomes final.</p>',
    "9": '<p><strong>kan men poiēsē karpon eis to mellon</strong> — if it then bears fruit in the coming year — the conditional is hopeful but not guaranteed; the vinedresser pleads for a chance, not a certainty. <strong>ei de mē ge, ekkopseis autēn</strong> — but if not, you will cut it down — the deadline is deferred, not abolished; the owner\'s patience accommodates the vinedresser\'s intercession but does not abandon the fruitfulness requirement. The parable ends without resolution: the audience must supply the ending. In the narrative context, Israel is at the year of deferral — the three years of Jesus\'s ministry giving way to one final year of intensified opportunity.</p>',
    "10": '<p><strong>Ēn de didaskōn en mia tōn synagōgōn en tois sabbasin</strong> — he was teaching in one of the synagogues on the Sabbath — the Sabbath healing of the bent woman (vv.10-17) is unique to Luke. The setting — synagogue, Sabbath — is the intersection of maximum communal witness and maximum halakhic scrutiny. The woman\'s presence in the synagogue despite her severe disability (<em>pneumati astheneia</em>, v.11) implies she maintained her religious practice throughout the eighteen years of her affliction.</p>',
    "11": '<p><strong>kai idou gynē ēn pneumati echousa astheneia etē dekaokto</strong> — and there was a woman who had a spirit of weakness for eighteen years — <em>pneuma astheneia</em> (spirit of infirmity/weakness) — Luke names a spiritual dimension to the physical condition (v.16 confirms: "bound by Satan"); this does not eliminate natural causation but adds a demonic oppression diagnosis. <em>Dekaokto etē</em> (eighteen years) — the same number as the tower victims (v.4), an intentional echo: these eighteen years of bondage parallel those eighteen deaths, both serving to illustrate the condition from which Jesus comes to liberate. <strong>kai ēn sygkyptousa kai mē dynamenē anakupsai eis to panteles</strong> — she was bent double and could not straighten up at all.</p>',
    "12": '<p><strong>idōn de autēn ho Iēsous prosephōnēsen kai eipen autē</strong> — seeing her, Jesus called to her and said — the initiative is entirely Jesus\'s: the woman makes no request, no approach. <em>Prosephōnēsen</em> (called out to, summoned by calling) is a public summons across the synagogue. <strong>Gynai, apolelalysai tēs astheneia sou</strong> — Woman, you have been released from your weakness — <em>apolelalysai</em> (perfect passive: you have been and remain released — the release is an accomplished fact declared before the laying on of hands) announces freedom before the physical restoration. The perfect tense is the word of liberation: the sentence is pronounced, the bondage broken.</p>',
    "13": '<p><strong>kai epethēken autē tas cheiras</strong> — and he laid his hands on her — the laying on of hands (<em>epitithēmi tas cheiras</em>) is the gesture of blessing and transfer: the same gesture used for healing (4:40), commissioning (Acts 6:6; 13:3), and gift of the Spirit (Acts 8:17-19). <strong>kai parachrēma anōrthōthē kai edoxazen ton Theon</strong> — and immediately she was made straight and was glorifying God — <em>anorthoō</em> (to straighten up, erect again — medical term for correcting a bent or collapsed structure; cf. Acts 15:16 "raise up the tent of David that has fallen") is the physical restoration. <em>Parachrēma</em> (immediately) is Luke\'s healing-stamp. <em>Edoxazen ton Theon</em> (was glorifying God) — the imperfect of continuous praise: she did not stop.</p>',
    "14": '<p><strong>apokritheis de ho archisyagōgos, aganaktōn hoti tō sabbatō etherapeusen ho Iēsous</strong> — the synagogue ruler answered, indignant because Jesus had healed on the Sabbath — <em>aganakteō</em> (to be indignant, greatly displeased — a strong word for righteous anger turned against Jesus) frames the synagogue ruler\'s objection as a principled defense of Sabbath law. <strong>eischen tō ochlō, Hex hēmerai eisin en hais dei ergazesthai; en autais oun erchomenoi therapeuesthe kai mē tē hēmera tou sabbatou</strong> — he said to the crowd: there are six days on which it is necessary to work; in those come and be healed and not on the Sabbath day — the reproof is addressed to the crowd (not directly to Jesus), probably to avoid direct confrontation; the halakhic point is technically sound within a strict Shammaite framework.</p>',
    "15": '<p><strong>apekrithē de autō ho Kyrios kai eipen, Hypokrita, hekastos hymōn tō sabbatō ou lyei ton boun autou ē ton onon apo tēs phatnēs kai apagagōn potizei</strong> — the Lord answered him and said: Hypocrites! Does not each of you on the Sabbath untie his ox or donkey from the manger and lead it away to water? — <em>Hypokritai</em> (Hypocrites — the plural indicts the synagogue leadership in general, not just the ruler). The argument is <em>qal va-homer</em> (light to heavy, a fortiori): if one may perform the labor of untying and leading animals on the Sabbath for their welfare (a permissive halakhic ruling accepted by most schools, m. Eruvin 2:1-4), how much more may one release a human being from bondage.</p>',
    "16": '<p><strong>tautēn de, thygatera Abraam ousan, hēn edēsen ho Satanas idou dekaokta etē</strong> — and this woman, being a daughter of Abraham, whom Satan has bound for eighteen years — <em>thygatera Abraam</em> (daughter of Abraham) restores the woman\'s full covenant identity: she is not defined by her disability or her gender\'s exclusion from the inner synagogue space but by her Abrahamic inheritance. <em>Hon edēsen ho Satanas</em> (whom Satan has bound — aorist: a specific binding at a point in time, followed by eighteen years of captivity) names the spiritual agency behind the physical condition. <strong>ouk edei lythēnai apo tou desmou toutou tē hēmera tou sabbatou</strong> — ought she not be loosed from this bond on the Sabbath day? — <em>dei</em> (it is necessary, it is morally required) inverts the ruler\'s "six working days" argument.</p>',
    "17": '<p><strong>kai tauta legontos autou katēschynonto pantes hoi antikeimenoi autō</strong> — and as he was saying these things all his opponents were put to shame — <em>kataischynō</em> (to put to shame, dishonor publicly — cf. Isa 41:11; 54:4 LXX) is the reversal of honor: those who claimed halakhic superiority are publicly shamed. <strong>kai pas ho ochlos echaire epi pasin tois endoxois tois ginomenois hyp autou</strong> — and all the crowd was rejoicing at all the glorious things being done by him — <em>endoxois</em> (glorious, magnificent things) is Luke\'s word for miraculous events that display divine glory (cf. 7:25; Acts 10:46). The crowd\'s joy is the positive counterpart to the opponents\' shame.</p>',
    "18": '<p><strong>Elegen oun, Tini homoia estin hē basileia tou Theou kai tini homoiōsō autēn</strong> — he said therefore: what is the kingdom of God like? and what shall I compare it to? — <em>homoios</em>/<em>homoioō</em> (like, to liken — the comparison-formula for parables) introduces the two kingdom-parables. The double question (<em>Tini homoia... kai tini homoiōsō</em>) is the rhetorical invitation to thought before the comparison is offered; it solicits the audience\'s creative engagement. The kingdom-parables follow the Sabbath healing as its interpretation: the liberation of the bent woman is an instance of the kingdom\'s arrival, now described through the lens of growth and pervasion.</p>',
    "19": '<p><strong>homoia estin kokkō sinapeōs, hon labōn anthrōpos ebalen eis kēpon heautou</strong> — it is like a mustard seed which a man took and threw into his garden — the mustard (<em>sinapi</em>) seed is proverbially small in rabbinic literature (b. Sanhedrin 91a: "as small as a grain of mustard"). <em>Kēpos</em> (garden — Luke\'s word; Matthew/Mark have "field") may reflect a Hellenistic context. <strong>kai ēyxēsen kai egeneto eis dendron</strong> — and it grew and became a tree — Luke\'s <em>dendron</em> (tree) is a larger growth than Mark\'s "larger than all garden plants"; Luke\'s version is more clearly hyperbolic. <strong>kai ta peteina tou ouranou kateskēnōsen en tois kladois autou</strong> — and the birds of the air nested in its branches — an allusion to Dan 4:12,21 (Ezek 17:23; 31:6) where a great tree shelters the nations: the kingdom\'s growth will accommodate all peoples.</p>',
    "20": '<p><strong>kai palin eipen, Tini homoiōsō tēn basileian tou Theou</strong> — again he said: what shall I compare the kingdom of God to? — the second question and second kingdom-parable maintains the paired structure (cf. the lost sheep/lost coin parables in ch.15; the two sons/prodigal in ch.15). The repetition of the question (<em>palin</em> = again) marks the separate parable; the yeast-parable supplements the mustard-seed by describing the kingdom\'s mode of pervasion rather than its mode of growth.</p>',
    "21": '<p><strong>homoia estin zymē, hēn labousa gynē enekrypsen eis aleurou sata tria heōs hou ezymōthē holon</strong> — it is like yeast which a woman took and hid in three measures of flour until it was all leavened — <em>zymē</em> (yeast, leaven) here is used positively, in contrast to 12:1 (the leaven of hypocrisy). The woman hides (<em>enkryptō</em> — to conceal, bury within) the yeast: the kingdom works invisibly from within, not through external imposition. <em>Sata tria</em> (three seahs — approximately 40 liters, enough flour for a feast for 100+ people; cf. Gen 18:6 where Sarah prepares three seahs for the divine visitors). The large quantity implies communal, abundant transformation. <em>Heōs hou ezymōthē holon</em> (until the whole was leavened) — complete, total pervasion.</p>',
    "22": '<p><strong>kai dieporeueto kata poleis kai kōmas didaskōn kai poreian poioumenos eis Ierousalēm</strong> — he was traveling through cities and villages teaching and making his way to Jerusalem — this verse is Luke\'s narrative hinge reminding the reader that the entire discourse of chs.12-13 occurs within the travel narrative (9:51-19:44). <em>Poreian poioumenos eis Ierousalēm</em> (making his journey toward Jerusalem) — <em>poreian poieomai</em> (to make a journey, pursue a course) uses the journey-language that defines the central section of Luke\'s Gospel. Every teaching occurs under the shadow of the destination.</p>',
    "23": '<p><strong>eipen de tis autō, Kyrie, ei oligoi hoi sōzomenoi</strong> — someone said to him: Lord, are only a few being saved? — the question was debated in Second Temple Judaism: how many of Israel would be saved in the eschatological age? Some traditions held that "all Israel has a share in the world to come" (m. Sanhedrin 10:1); others expected only a remnant (4 Ezra 8:1-3: "the Most High made this world for the sake of many, but the world to come for the sake of few"). Jesus refuses to answer the numerical question directly and redirects to the urgency of personal decision.</p>',
    "24": '<p><strong>ho de eipen pros autous, Agōnizesthe eiselthein dia tēs stenēs thyras</strong> — he said to them: strive to enter through the narrow door — <em>agōnizomai</em> (to strive, struggle, compete — the athletic-contest word; from <em>agōn</em>, the Greek athletic competition; used by Paul in 1 Cor 9:25; Col 1:29; 1 Tim 6:12) describes effortful, concentrated striving. <em>Stenē thura</em> (narrow door — Matthew\'s version has "narrow gate" in a different context, Mt 7:13-14). The narrowness does not mean restriction to a few but difficulty of entry: the door requires focused intention. <strong>hoti polloi, legō hymin, zētēsousin eiselthein kai ouk ischysousin</strong> — because many, I tell you, will seek to enter and will not be able.</p>',
    "25": '<p><strong>aph hou an egerthē ho oikodespotēs kai apokleisē tēn thyran</strong> — once the master of the house gets up and shuts the door — the closing of the door is the definitive moment of eschatological division: before its closing, entry is possible; after, impossible. <em>Apokleisē</em> (to shut, lock — to close definitively against reentry) is the aorist of finality. <strong>kai arxēsthe exō hestanai kai krouein tēn thyran legontes, Kyrie, anoixon hēmin</strong> — and you begin to stand outside and knock at the door saying: Lord, open to us — <em>Kyrie</em> (Lord) is addressed to the one who has shut the door; the address is that of those who assumed relationship but lacked entry. <strong>kai apokritheis erei hymin, Ouk oida hymas pothen este</strong> — answering he will say: I do not know you, where you are from.</p>',
    "26": '<p><strong>tote arxesthe legein, Ephagomen enōpion sou kai epiomen kai en tais plateiais hēmōn edidaxas</strong> — then you will begin to say: we ate and drank before you and you taught in our streets — the three claims are social proximity to Jesus: table-fellowship (<em>ephagomen enōpion sou</em> = we ate before/with you), shared drink, and reception of his teaching. None of these constitute the relationship of discipleship; proximity without personal commitment and transformation is not the basis of entry. The claims echo Lk 4:23 ("whatever we heard done in Capernaum, do here also") — familiarity without faith.</p>',
    "27": '<p><strong>kai erei legōn hymin, Ouk oida hymas pothen este; apostēte ap emou, pantes ergatai adikias</strong> — and he will say, speaking to you: I do not know you, where you are from; depart from me, all workers of iniquity — <em>Ouk oida hymas pothen este</em> (I do not know you, where you are from) repeated for emphasis: the denial of relationship is total. <em>Ergatai adikias</em> (workers of iniquity — a phrase from Ps 6:8 LXX: "depart from me all workers of iniquity") identifies those who claimed proximity to Jesus but practiced injustice as Psalm 6\'s evildoers. The citation grounds the saying in the Psalter\'s lament-tradition.</p>',
    "28": '<p><strong>ekei estai ho klauthmos kai ho brygmos tōn odontōn</strong> — there will be the weeping and the gnashing of teeth — the stereotyped eschatological expression of grief and rage in final exclusion (Matthew uses it 6x; Luke only here). <strong>hotan opsēsthe Abraam kai Isaak kai Iakōb kai pantas tous prophētas en tē basileia tou Theou, hymas de ekballomenous exō</strong> — when you will see Abraham and Isaac and Jacob and all the prophets in the kingdom of God and yourselves thrown out — the excluded see the patriarchs inside the kingdom; the vision of inclusion they assumed for themselves belongs to others while they are <em>ekballomenous exō</em> (thrown outside).</p>',
    "29": '<p><strong>kai hēxousin apo anatolōn kai dysmōn kai apo borra kai notou kai anaklithēsontai en tē basileia tou Theou</strong> — and they will come from east and west and from north and south and will recline at table in the kingdom of God — <em>apo anatolōn kai dysmōn kai apo borra kai notou</em> (from east and west and from north and south) is the four-direction formula for universal inclusion (cf. Isa 49:12; Ps 107:3; Zech 8:7). <em>Anaklithēsontai</em> (will recline at table) — the banquet posture; the kingdom is the eschatological feast where the unexpected guests from the margins of the world have places set for them. The reversal operates at the macro scale: those who thought themselves insiders will watch outsiders dine.</p>',
    "30": '<p><strong>kai idou eisin eschatoi hoi esontai prōtoi kai eisin prōtoi hoi esontai eschatoi</strong> — and behold, there are last who will be first and first who will be last — the reversal aphorism (cf. 18:14; Mt 20:16; Mk 10:31) summarizes the kingdom\'s counter-intuitive economy. <em>Eschatoi</em>/<em>prōtoi</em> (last/first) applies both to the unexpected Gentile guests reclining in the kingdom (v.29) and to the presumptuous insiders excluded (v.28). The reversal is not guaranteed for everyone outside or denied to everyone inside; it is the description of the kingdom\'s surprise: ethnic and religious advantage does not convert to eschatological position without the faith-response.</p>',
    "31": '<p><strong>En autē tē hōra prosēlthon tines Pharisaioi legontes autō, Exelthe kai poreuou enteuthen, hoti Hērōdēs thelei se apokteinai</strong> — at that very hour some Pharisees came saying to him: get out and go from here, because Herod wants to kill you — a surprising warning from Pharisees who are typically hostile (though some Pharisees are hospitable in Luke: 7:36; 11:37; 14:1). The warning may be genuine concern, may be a Herodian attempt to drive Jesus from Perea (Herod\'s territory), or may be both. Herod Antipas had already killed John the Baptist (3:19-20; 9:9) and had desired to see Jesus (9:9; 23:8).</p>',
    "32": '<p><strong>kai eipen autois, Poreuthentes eipate tē alōpeki tautē</strong> — go and say to that fox — <em>alōpēx</em> (fox) is a term of contempt in both Greek and Jewish usage: cunning, destructive to small animals, not the noble lion. Jesus\'s public characterization of Herod as a fox is political: it names the petty-prince quality of Herod\'s threats. <strong>Idou ekballō daimonia kai iaseis apotelō sēmeron kai aurion kai tē tritē teleioumai</strong> — behold, I cast out demons and complete healings today and tomorrow and on the third day I am perfected — <em>teleioumai</em> (I am perfected, completed, brought to my goal — cf. Heb 2:10; 5:9; 12:23 for the same "perfection through suffering" language) is a Passion reference: the "third day" is the resurrection day that completes the journey.</p>',
    "33": '<p><strong>plēn dei me sēmeron kai aurion kai tē echomenē poreuesthai</strong> — but it is necessary for me today and tomorrow and the next day to travel — <em>dei</em> (divine necessity — Luke\'s strongest compulsion word) appears again: the journey to Jerusalem is not chosen but appointed. <strong>hoti ouk endechetai prophētēn apolesthai exō Ierousalēm</strong> — because it is not acceptable for a prophet to perish outside Jerusalem — <em>ouk endechetai</em> (it is not acceptable, not possible, not fitting — an ironic statement) frames Jerusalem\'s murderous history with prophets as the destination for the prophet who must die. The irony is double: Jerusalem is simultaneously the city of the temple (God\'s presence) and the city that kills his messengers.</p>',
    "34": '<p><strong>Ierousalēm, Ierousalēm, hē apokteinousa tous prophētas kai lithobologousa tous apestalmenous pros autēn</strong> — Jerusalem, Jerusalem, the one killing the prophets and stoning those sent to her — the double vocative (<em>Ierousalēm, Ierousalēm</em>) is the mourning address, the form of lament (cf. 2 Sam 18:33 "O Absalom, my son"; Jer 22:29 "O land, land, land"). <em>Hē apokteinousa ... kai lithobologousa</em> (the one killing ... and stoning) — present participles: the city is characterized by its persistent rejection of prophetic address. <strong>posakis ēthelēsa episynaxai ta tekna sou hon tropon ornis tēn heautēs nossian hypo tas pterygas</strong> — how often I desired to gather your children as a bird her nest under her wings — the maternal-bird image (Deut 32:11; Ps 91:4; Ruth 2:12; Isa 31:5) of YHWH\'s protective sheltering; Jesus speaks with divine longing.</p>',
    "35": '<p><strong>kai ouk ēthelēsate</strong> — and you were not willing — the single counter to the divine desire: human refusal. The perfect freedom of rejection stands against the perfect compassion of the divine longing. <strong>idou aphietai hymin ho oikos hymōn</strong> — behold, your house is left to you desolate — <em>ho oikos hymōn</em> (your house) is the temple (cf. Jer 12:7; 22:5 LXX "your house is left desolate"); the divine presence departs from the house that rejects its Lord. <strong>legō de hymin, ou mē idēte me heōs [hēxei hote] eipēte, Eulogēmenos ho erchomenos en onomati Kyriou</strong> — I tell you, you will not see me until you say: Blessed is the one coming in the name of the Lord — Ps 118:26 (LXX), the Hallel Psalm quoted at the triumphal entry (19:38). The suspension of the divine presence ends when Jerusalem greets its King; the verse is simultaneously a judgment and a promise.</p>',
  }
}

def main():
    existing = load_comm('mkt-original', 'luke')
    merge_comm(existing, LUKE)
    save_comm('mkt-original', 'luke', existing)
    print('Luke mkt-original chs 12-13 written.')

if __name__ == '__main__':
    main()
